output.sparql:
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
SELECT ?club ?clubLabel(COUNT(DISTINCT ?season) AS ?count) WHERE {
  VALUES ?club {
    wd:Q2521385 wd:Q249679 wd:Q2272176
  }
  ?club p:P166 ?stmt .
  ?stmt ps:P166 wd:Q2637699 .
  OPTIONAL {
    ?club rdfs:label ?clubLabel
    FILTER(lang(?clubLabel) = 'en')
  }
}
GROUP BY ?club ?clubLabel
ORDER BY DESC(?count)
LIMIT 1

args.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>

SELECT ?club ?clubLabel (COUNT(?season) AS ?woodenSpoons)
WHERE {
  VALUES ?club { wd:Q2521385 wd:Q249679 wd:Q2272176 }
  ?club p:P3490 ?seasonStatement .
  ?seasonStatement ps:P3490 ?season ;
                   pq:P4466 ?position .
  BIND(xsd:integer(?position) AS ?posInt)
  {
    SELECT ?season (MAX(xsd:integer(?p)) AS ?maxPos)
    WHERE {
      ?anyTeam p:P3490 ?stmt .
      ?stmt ps:P3490 ?season ;
            pq:P4466 ?p .
      FILTER isNumeric(?p)
    }
    GROUP BY ?season
  }
  FILTER (?posInt = ?maxPos)
  OPTIONAL { ?club rdfs:label ?clubLabel FILTER (lang(?clubLabel) = 'en') }
}
GROUP BY ?club ?clubLabel
ORDER BY DESC(?woodenSpoons)
LIMIT 1
